// ১. ইনপুট নেওয়া
const pendingMessages = $input.all();
if (pendingMessages.length === 0) return [{ json: { isValid: false, reason: "No data in sheet" } }];

// ২. বর্তমান প্রসেসের আইডি (Webhook থেকে)
let currentMid;
try {
    currentMid = String($("Webhook").first().json.body.entry[0].messaging[0].message.mid).trim();
} catch (e) {
    return [{ json: { isValid: false, reason: "Webhook Data Error" } }];
}

// ৩. শিটের শেষ আইটেম এবং রো নম্বর বের করা
const lastItem = pendingMessages[pendingMessages.length - 1];
const lastMessageInSheet = String(lastItem.json["Message Id"]).trim(); 

// শিট থেকে রো নম্বরটি নেওয়া (n8n সাধারণত 'row_number' হিসেবে দেয়)
// যদি আপনার শিটে সরাসরি 'Row' কলাম থাকে তবে lastItem.json["Row"] ব্যবহার করুন
const rowNumber = lastItem.json.row_number || lastItem.pairedItem.itemIndex + 2; 
// (+২ করা হয়েছে কারণ শিটের হেডার এবং ইন্ডেক্স ব্যালেন্স করার জন্য)

// ৪. তুলনা করা
const isLatest = currentMid === lastMessageInSheet;

// ৫. আউটপুট
const combinedText = isLatest ? pendingMessages.map(item => item.json.Message).join(" \n ") : "";

return [{
    json: {
        isValid: isLatest,
        my_id: currentMid,
        sheet_id: lastMessageInSheet,
        row_number: rowNumber, // এটি এখন আউটপুটে যাবে
        match_status: isLatest ? "MATCHED" : "MISMATCH",
        sender_id: pendingMessages[0].json.Sender_ID,
        combined_message: combinedText
    }
}];

const aiOutput = $json.output || "";
const buttons = [];
const seen = new Set();
const regex = /\[(.*?)\]/g; 
let match;
let counter = 1;

// বাটন বা অপশনগুলো খোঁজা হচ্ছে
while ((match = regex.exec(aiOutput)) !== null) {
  let title = match[1].trim();
  if (!seen.has(title)) {
    buttons.push({ 
      "title": `${counter}. ${title.substring(0, 15)}`, 
      "payload": `OPTION_${counter}` 
    });
    seen.add(title);
    counter++;
  }
}

// টেক্সট ক্লিন করা এবং অতিরিক্ত লম্বা টেক্সট ছেঁটে ফেলা
let cleanText = aiOutput.replace(/\[.*?\]/g, '')
                        .replace(/\*/g, '')
                        .replace(/\s+/g, ' ')
                        .trim();

// মেসেঞ্জারের জন্য ১০০০ ক্যারেক্টারের বেশি টেক্সট না পাঠানোই ভালো
return {
  output_text: cleanText.length > 500 ? cleanText.substring(0, 500) + "..." : cleanText,
  dynamic_buttons: buttons,
  has_buttons: buttons.length > 0
}
